mapper.select:
SELECT s.id, s.workflow_id, s.stat_date,
       s.total_runs, s.success_count, s.failed_count, s.running_count,
       s.avg_duration_ms, s.max_duration_ms, s.min_duration_ms,
       s.total_tokens, s.human_tasks_count, s.human_tasks_avg_minutes
FROM workflow_stats s
WHERE 1 = 1
    AND s.workflow_id = #{workflowId}
    AND s.stat_date >= #{startDate}
    AND s.stat_date <= #{endDate}
ORDER BY s.stat_date DESC
